mapper.insert:
INSERT INTO ISSUE_CHANGE_LOG_MAP ( ISSUE_ID, CHANGE_LOG_ID ) SELECT ISSUE_ID, #{changeLogId,jdbcType=OTHER,typeHandler=com.devtrace.manager.common.config.UuidTypeHandler} FROM ISSUE WHERE ISSUE_KEY IN
#{issueKey}
ON CONFLICT DO NOTHING

mapper.delete:
DELETE FROM ISSUE_CHANGE_LOG_MAP
WHERE CHANGE_LOG_ID IN (
    SELECT CHANGE_LOG_ID
    FROM VCS_CHANGE_LOG
    WHERE PROJECT_ID = #{_parameter,jdbcType=OTHER,typeHandler=com.devtrace.manager.common.config.UuidTypeHandler}
)

DELETE FROM VCS_CHANGE_FILE
WHERE CHANGE_LOG_ID IN (
    SELECT CHANGE_LOG_ID
    FROM VCS_CHANGE_LOG
    WHERE PROJECT_ID = #{_parameter,jdbcType=OTHER,typeHandler=com.devtrace.manager.common.config.UuidTypeHandler}
)

mapper.select:
SELECT CHANGE_LOG_ID, PROJECT_ID, VCS_TYPE, REVISION_NO, AUTHOR, CHANGED_AT, MESSAGE, CREATED_AT FROM VCS_CHANGE_LOG
AND PROJECT_ID = #{projectId,jdbcType=OTHER,typeHandler=com.devtrace.manager.common.config.UuidTypeHandler}
AND VCS_TYPE = #{vcsType}
ORDER BY CHANGED_AT DESC NULLS LAST, CREATED_AT DESC

SELECT CHANGE_FILE_ID, CHANGE_LOG_ID, FILE_PATH, CHANGE_TYPE FROM VCS_CHANGE_FILE WHERE CHANGE_LOG_ID IN
#{changeLogId,jdbcType=OTHER,typeHandler=com.devtrace.manager.common.config.UuidTypeHandler}
ORDER BY FILE_PATH ASC

SELECT M.CHANGE_LOG_ID, I.ISSUE_KEY FROM ISSUE_CHANGE_LOG_MAP M INNER JOIN ISSUE I ON M.ISSUE_ID = I.ISSUE_ID WHERE M.CHANGE_LOG_ID IN
#{changeLogId,jdbcType=OTHER,typeHandler=com.devtrace.manager.common.config.UuidTypeHandler}
ORDER BY I.ISSUE_KEY ASC
